let movers = [];
let vDraw;

const NUM_MOVERS = 12;

// ---- noise grid settings ----
const CELL = 2;          // grid cell size (px). smaller = more detail, slower
let zoff = 0;             // time dimension for animated noise (set to 0 and don't change for static)
const NOISE_SCALE = 0.01; // how zoomed in the noise is
const Z_SPEED = 0.005;     // how fast the noise animates

function setup() {
  createCanvas(600, 400);
  noStroke();

  vDraw = new VectorDrawer({
    headScale: 0.06,
    weightScale: 0.03,
    minHead: 6,
    maxHead: 30
  });

  for (let i = 0; i < NUM_MOVERS; i++) {
    let m = new Mover(random(width), random(height));
    let angle = random(TWO_PI);
    let speed = random(2, 4);
    m.velocity = p5.Vector.fromAngle(angle).mult(speed);
    movers.push(m);
  }
}

function draw() {
  drawNoiseGrid(); // <-- background grid

  for (let mover of movers) {
    mover.update();
    mover.bounceEdges();
    mover.display(vDraw);
  }
}

function drawNoiseGrid() {
  // draw a grayscale grid based on Perlin noise
  for (let y = 0; y < height; y += CELL) {
    for (let x = 0; x < width; x += CELL) {
      const n = noise(x * NOISE_SCALE, y * NOISE_SCALE, zoff); // 0..1
      const c = map(n, 0, 1, 0, 255); // black..white
      noStroke();
      fill(c);
      rect(x, y, CELL, CELL);
    }
  }

  // animate the noise over time (comment out for static)
  zoff += Z_SPEED;
}

