// Flow-field mover with anti-clumping separation + wrap edges + configurable visuals.

class Mover {
  constructor(x = 0, y = 0, opts = {}) {
    this.position = createVector(x, y);
    this.velocity = createVector();
    this.acceleration = createVector();

    // =========================
    // Motion tuning
    // =========================
    this.maxSpeed = opts.maxSpeed ?? 3.5;
    this.fieldInfluence = opts.fieldInfluence ?? 0.25;

    // Separation (anti-clump)
    this.sepDist = opts.sepDist ?? 50;           // neighborhood radius
    this.sepStrength = opts.sepStrength ?? 1.2;  // multiplier on separation force
    this.sepMaxForce = opts.sepMaxForce ?? 0.25; // cap steering force

    // Optional: tiny jitter to avoid locking into same streamlines
    this.jitter = opts.jitter ?? 0.02;
    this.jitterScale = opts.jitterScale ?? 0.01;
    this._joff = random(1000);

    // =========================
    // Visual tuning
    // =========================
    this.radius = opts.radius ?? 20;

    this.fillCol = opts.fillCol ?? 255;
    this.strokeCol = opts.strokeCol ?? 0;
    this.strokeW = opts.strokeW ?? 2;

    this.showArrow = opts.showArrow ?? true;

    this.arrowMode = opts.arrowMode ?? "speed"; // "fixed" | "speed"
    this.arrowLenScale = opts.arrowLenScale ?? 1.2; // fixed mode
    this.arrowSpeedScale = opts.arrowSpeedScale ?? 10; // speed mode
    this.arrowMinLen = opts.arrowMinLen ?? 6;
    this.arrowMaxLen = opts.arrowMaxLen ?? 40;

    this.centerDot = opts.centerDot ?? true;
    this.centerDotSize = opts.centerDotSize ?? 4;
    this.centerDotCol = opts.centerDotCol ?? 0;
  }

  applyForce(f) {
    this.acceleration.add(f);
  }

  followField(field) {
    const force = field.getVectorAt(this.position.x, this.position.y);
    force.mult(this.fieldInfluence);
    // treat as force (goes into acceleration), not direct velocity edit
    this.applyForce(force);
  }

  // repulsion from nearby movers (prevents clumping)
  separate(others) {
    let steer = createVector(0, 0);
    let count = 0;

    for (let o of others) {
      if (o === this) continue;

      const d = p5.Vector.dist(this.position, o.position);
      if (d > 0 && d < this.sepDist) {
        let diff = p5.Vector.sub(this.position, o.position);
        diff.normalize();
        diff.div(d); // stronger when closer
        steer.add(diff);
        count++;
      }
    }

    if (count > 0) {
      steer.div(count);

      // convert to steering force
      steer.setMag(this.maxSpeed);
      steer.sub(this.velocity);
      steer.limit(this.sepMaxForce);
      steer.mult(this.sepStrength);

      this.applyForce(steer);
    }
  }

  // tiny personal noise force to prevent "lane locking"
  applyJitter() {
    if (this.jitter <= 0) return;

    const a =
      noise(
        this.position.x * this.jitterScale,
        this.position.y * this.jitterScale,
        this._joff
      ) *
      TWO_PI *
      2;

    const f = p5.Vector.fromAngle(a).mult(this.jitter);
    this.applyForce(f);
    this._joff += 0.01;
  }

  update() {
    this.velocity.add(this.acceleration);
    this.velocity.limit(this.maxSpeed);
    this.position.add(this.velocity);
    this.acceleration.mult(0);
  }

  wrapEdges() {
    const r = this.radius;

    if (this.position.x > width + r) this.position.x = -r;
    if (this.position.x < -r) this.position.x = width + r;

    if (this.position.y > height + r) this.position.y = -r;
    if (this.position.y < -r) this.position.y = height + r;
  }

  _computeArrowLen() {
    if (this.arrowMode === "speed") {
      const len = this.velocity.mag() * this.arrowSpeedScale;
      return constrain(len, this.arrowMinLen, this.arrowMaxLen);
    }
    return this.radius * this.arrowLenScale;
  }

  display(vectorDrawer) {
    // ball
    push();
    fill(this.fillCol);
    noStroke();
    circle(this.position.x, this.position.y, this.radius * 2);

    if (this.centerDot) {
      noStroke();
      fill(this.centerDotCol);
      circle(this.position.x, this.position.y, this.centerDotSize);
    }
    pop();

    // arrow (velocity)
    if (this.showArrow) {
      const v = this.velocity.copy();
      if (v.mag() > 0.0001) {
        v.setMag(this._computeArrowLen());

        vectorDrawer.drawFromPoints(
          this.position.x,
          this.position.y,
          this.position.x + v.x,
          this.position.y + v.y
        );
      }
    }
  }
}

