let movers = [];
let vDraw;
let vecGrid;

const NUM_MOVERS = 200;

function setup() {
  createCanvas(400, 400);

  // Shared drawer for grid + movers
  vDraw = new VectorDrawer({
    strokeCol: "red",
    fillCol: 0,
    headScale: 0.06,
    weightScale: 0.03,
    minHead: 0.02,
    maxHead: 30,
    minWeight: 1,
    maxWeight: 6,
  });

  vecGrid = new VectorGrid({
    cell: 10,
    noiseScale: 0.0001,
    zSpeed: 1,
    arrowScale: 0.42,
    bg: 245,
  });

