  for (let i = 0; i < NUM_MOVERS; i++) {
    const m = new Mover(random(width), random(height), {
      radius: 5,
      fillCol: "blue",
      strokeCol: null,
      strokeW: 2,

      showArrow: true,
      arrowMode: "speed",
      arrowSpeedScale: 10,
      arrowMaxLen: 40,

