      tile.y - tile.size / 2,
      tile.x + tile.size / 2,
      tile.y + tile.size / 2,
    );
  },
};

class Tile {
  constructor(x, y, opts = {}) {
    this.x = x;
    this.y = y;
    this.size = opts.size ?? 10;
    this.type = opts.type ?? 0;
  }

  render() {
    const renderer = TILE_RENDERERS[this.type];
    if (renderer) renderer(this);
  }
}

