      "#ff0000",
      "#00ffff",
      "#ff0000",
      "#ff0000",
      "#00ffff",
      "#ff0000",
    ],

    minorColors: [
      "#ff0000",
      "#00ffff",
      "#00ffff",
      "#ff0000",
      "#ff0000",
      "#00ffff",
      "#ff0000",
      "#ff0000",
      "#00ffff",
      "#ff0000",
    ],
  });

  light1 = new Light(width * 0.8, height * 0.45, {
    size: 30,

    majorColors: [
      "#ff0000",
      "#00ffff",
      "#ff0000",
      "#ff0000",
      "#00ffff",
      "#ff0000",
    ],

    minorColors: [
      "#ff0000",
      "#00ffff",
      "#ff0000",
      "#ff0000",
      "#00ffff",
      "#ff0000",
    ],
  });
