    m.followField(vecGrid);
    m.separate(movers);
    m.applyJitter();

    m.update();
    m.wrapEdges();
    m.display(vDraw);
  }
  light.render();
  drawUnevenCurve();
  light1.render();
}

function drawUnevenCurve() {
  push();
  noStroke();
  fill(0);

  const steps = 140;
  const baseThickness = 0.05;

  // 👇 YOU control these
  const yStart = height * 0.65; // left side Y
  const yEnd = height * 0.35; // right side Y

  beginShape(TRIANGLE_STRIP);

  for (let i = 0; i <= steps; i++) {
    let t = i / steps;

    let x = lerp(0, width, t);

    // Linear interpolation between left & right
    let baseY = lerp(yStart, yEnd, t);

    // Add curve shape on top
    let curveOffset = sin(t * PI) * 30;

    let y = baseY + curveOffset;

    // uneven thickness
    let n = noise(t * 4, frameCount * 0.01);
    let thickness = baseThickness + map(n, 0, 1, -1, 3);

    vertex(x, y - thickness);
    vertex(x, y + thickness);
  }

  endShape();
  pop();
}

