class FreeNeutron extends Mover {
  constructor(x, y, opts = {}) {
    super(x, y);

    this.radius = opts.radius ?? 1.2;
    this.life = opts.life ?? 220;
    this.energy = opts.energy ?? 1.0;

    this.hasHit = false;
    this.dead = false;
  }

