// spatialHash.js
// spatialHash.js
class SpatialHash {
  constructor(cellSize = 20) {
    this.cellSize = cellSize;
    this.map = new Map();
  }

  _key(cx, cy) {
    return `${cx},${cy}`;
  }

  _cell(x, y) {
    return {
      cx: floor(x / this.cellSize),
      cy: floor(y / this.cellSize),
    };
  }

  build(items) {
    this.map.clear();
    for (const it of items) {
      // skip atoms that can't be hit
      if (it.dead || it.fissioned || it.exploding) continue;

      const { cx, cy } = this._cell(it.position.x, it.position.y);
      const k = this._key(cx, cy);

      if (!this.map.has(k)) this.map.set(k, []);
      this.map.get(k).push(it);
    }
  }

  queryNeighbors(x, y) {
    const { cx, cy } = this._cell(x, y);
    const out = [];

    // check this cell + 8 neighbors
    for (let oy = -1; oy <= 1; oy++) {
      for (let ox = -1; ox <= 1; ox++) {
        const k = this._key(cx + ox, cy + oy);
        const bucket = this.map.get(k);
        if (bucket) out.push(...bucket);
      }
    }

    return out;
  }
}

