    const vx = x + cos(a) * r;
    const vy = y + sin(a) * r;
    vertex(vx, vy);
  }
  endShape(CLOSE);
}

class FissileAtom extends Mover {
  constructor(x, y, opts = {}) {
    super(x, y);

    this.baseRadius = opts.baseRadius ?? 2;
    this.growth = opts.growth ?? 2.5;
    this.radius = this.baseRadius;

    // Instability system
    this.instability = 0; // 0..1+
    this.threshold = opts.threshold ?? 1.0;

    this.absorbGain = opts.absorbGain ?? 0.28;
    this.baseDecay = opts.baseDecay ?? 0.00002;

    // Explosion state
    this.exploding = false;
    this.explosionTimer = 0;

    // Spent state
    this.fissioned = false;

    // explosion visual scale
    this._boomScale = 0;
  }

  updateAtom() {
    if (this.dead) return;

    // exploding countdown
    if (this.exploding) {
      this.explosionTimer--;
      this._boomScale = lerp(this._boomScale, 1.0, 0.35);

      if (this.explosionTimer <= 0) {
        this.exploding = false;
        this.fissioned = true;

        // remove atom entirely
        this.dead = true;
      }
      return;
    }

    if (this.fissioned) return;

    // passive drift toward instability
    this.instability += this.baseDecay;
    this.instability = constrain(this.instability, 0, 1.6);

    // grow as instability increases
    const t = constrain(this.instability, 0, 1);
    this.radius = this.baseRadius + t * this.growth;
  }

  absorb(neutron) {
    if (this.dead || this.fissioned || this.exploding) return;

    const energy = neutron.energy ?? 1.0;
    const sensitivity = 1 + pow(this.instability, 2) * 2;

    this.instability += this.absorbGain * energy * sensitivity;
  }

  readyToFission() {
    return (
      !this.dead &&
      !this.fissioned &&
      !this.exploding &&
      this.instability >= this.threshold
    );
  }

  fission() {
    this.exploding = true;
    this.explosionTimer = 10;
    this._boomScale = 0;

    const newborn = [];
    const count = floor(random(4, 6));

    for (let i = 0; i < count; i++) {
      const angle = random(TWO_PI);
      const speed = random(2.5, 6.0);

      const nx = this.position.x + cos(angle) * this.radius;
      const ny = this.position.y + sin(angle) * this.radius;

      const n = new FreeNeutron(nx, ny, {
        life: floor(random(140, 240)),
        energy: random(0.8, 1.2),
        radius: 1,
      });

      n.velocity = p5.Vector.fromAngle(angle).mult(speed);
      newborn.push(n);
    }

    return newborn;
  }

  display() {
    if (this.dead) return;

    push();
    noStroke();

    const x = this.position.x;
    const y = this.position.y;

    if (this.exploding) {
      fill("#690375");
      const r = (this.radius * 2.2) * (1.0 + this._boomScale * 0.6);
      drawHex(x, y, r);
      pop();
      return;
    }

    fill("#C14953");
    drawHex(x, y, this.radius);

    pop();
  }
}

