const TILE_RENDERERS = {
  0: (tile) => {
    const s = tile.size;
    const pad = s * 0.18;

    const topRightX = tile.x + s - pad - s * 0.18;
    const topRightY = tile.y + pad + s * 0.18;

    const bottomLeftX = tile.x + pad + s * 0.18;
    const bottomLeftY = tile.y + s - pad - s * 0.18;

    const rA = s * 0.1;
    const rB = s * 0.22;

    const oscA = map(tile.t, 0, 1, 5, 8);
    const oscB = map(tile.t, 0, 1, 10, 4);

    const sidesA = round(oscA);
    const sidesB = round(oscB);

    const colA = lerpColor(color(tile.colorS), color(tile.colorT), tile.t);
    const colB = lerpColor(color(tile.colorT), color(tile.colorS), tile.t);

    noStroke();

    fill(colA);
    drawPolygon(topRightX, topRightY, rA, sidesA, -HALF_PI);

    fill(colB);
    drawPolygon(bottomLeftX, bottomLeftY, rB, sidesB, -HALF_PI);
  },
  1: (tile) => {
    const s = tile.size;

    const cx = tile.x + s * 0.5;
    const cy = tile.y + s * 0.5;

    const centerR = s * 0.16;
    const orbitR = s * 0.25;
    const satelliteR = s * 0.09;

    const angle = tile.t * TWO_PI;
    const angle2 = angle + PI;

    const x1 = cx + cos(angle) * orbitR;
    const y1 = cy + sin(angle) * orbitR;

    const x2 = cx + cos(angle2) * orbitR;
    const y2 = cy + sin(angle2) * orbitR;

    const colCenter = lerpColor(color(tile.colorS), color(tile.colorT), tile.t);
    const colOrbit = lerpColor(color(tile.colorT), color(tile.colorS), tile.t);

    noStroke();

    fill(colCenter);
    drawPolygon(cx, cy, centerR, 6, -HALF_PI);

    fill(colOrbit);
    drawPolygon(x1, y1, satelliteR, 8, -HALF_PI + angle);

    fill(colOrbit);
    drawPolygon(x2, y2, satelliteR, 8, -HALF_PI - angle);
  },
};

function drawPolygon(cx, cy, radius, sides, rotation = 0) {
  sides = max(3, floor(sides));

  beginShape();
  for (let i = 0; i < sides; i++) {
    const a = rotation + (TWO_PI * i) / sides;
    const x = cx + cos(a) * radius;
    const y = cy + sin(a) * radius;
    vertex(x, y);
  }
  endShape(CLOSE);
}

class Tile {
  constructor(x, y, opts = {}) {
    this.x = x;
    this.y = y;
    this.size = opts.size ?? 10;
    this.type = opts.type ?? 0;
    this.t = opts.t ?? 0;

    this.colorP = opts.colorP ?? "yellow";
    this.colorS = opts.colorS ?? "red";
    this.colorT = opts.colorT ?? "blue";

    this.cx = opts.cx ?? width / 2;
    this.cy = opts.cy ?? height / 2;
    this.index = opts.index ?? 0;

    this.updateType = opts.updateType ?? "indexOffset";
    this.timeMultiplier = opts.timeMultiplier ?? 0.1;

    this.rotate = opts.rotate ?? 0; // 0, 1, 2, 3

    this.d = dist(this.x, this.y, this.cx, this.cy);
  }

  render() {
    const renderer = TILE_RENDERERS[this.type];
    if (!renderer) return;

    const angle = (this.rotate % 4) * HALF_PI;

    push();

    // move to tile center
    translate(this.x + this.size / 2, this.y + this.size / 2);
    rotate(angle);

    // local tile space starts at top-left of tile
    translate(-this.size / 2, -this.size / 2);

    // render in local space
    renderer({
      ...this,
      x: 0,
      y: 0,
    });

    pop();
  }

  update(globalTime) {
    let d = this.d;
    let phase = sin(globalTime * this.timeMultiplier);

    switch (this.updateType) {
      case "indexOffset":
        phase = sin(globalTime * this.timeMultiplier + this.index * 0.1);
        break;

      case "radialWave":
        phase = sin(globalTime * this.timeMultiplier + d * 0.05);
        break;

      case "ripple":
        phase = sin(globalTime * this.timeMultiplier - d * 0.08);
        break;

      case "horizontal":
        phase = sin(globalTime * this.timeMultiplier + this.x * 0.05);
        break;

      case "vertical":
        phase = sin(globalTime * this.timeMultiplier + this.y * 0.05);
        break;

      case "diagonal":
        phase = sin(
          globalTime * this.timeMultiplier + (this.x + this.y) * 0.04,
        );
        break;

      case "checker": {
        let cell = floor(this.x / this.size) + floor(this.y / this.size);
        phase = sin(globalTime * this.timeMultiplier + cell * PI);
        break;
      }

      case "noise":
        this.t = noise(
          this.x * 0.05,
          this.y * 0.05,
          globalTime * this.timeMultiplier,
        );
        return;

      default:
        phase = sin(globalTime * this.timeMultiplier);
        break;
    }

    this.t = map(phase, -1, 1, 0, 1);
  }
}

