// particle.js
class Particle {
  constructor(x, y, opts = {}) {
    this.x = x;
    this.y = y;

    this.size = opts.size ?? 8;

    this.vx = opts.vx ?? random(-1, 1);
    this.vy = opts.vy ?? random(-2, -0.5);

    this.ax = opts.ax ?? 0;
    this.ay = opts.ay ?? 0.05;

    this.life = opts.life ?? 255;
    this.decay = opts.decay ?? 3;
  }

  update() {
    this.vx += this.ax;
    this.vy += this.ay;

    this.x += this.vx;
    this.y += this.vy;

    this.life -= this.decay;
  }

  render() {
    noStroke();
    fill(255, this.life);
    circle(this.x, this.y, this.size);
  }

  isDead() {
    return this.life <= 0;
  }
}

