class Emitter {
  constructor(x, y, opts = {}) {
    this.x = x;
    this.y = y;

    this.rate = opts.rate ?? 2;
    this.particles = [];
  }

  emit() {
    for (let i = 0; i < this.rate; i++) {
      this.particles.push(
        new Particle(this.x, this.y, {
          size: random(4, 10),
          vx: random(-1, 1),
          vy: random(-3, -1),
          life: 255
        })
      );
    }
  }

  update() {
    for (let i = this.particles.length - 1; i >= 0; i--) {
      const p = this.particles[i];

      p.update();

      if (p.isDead()) {
        this.particles.splice(i, 1);
      }
    }
  }

  render() {
    for (const p of this.particles) {
      p.render();
    }
  }

  run() {
    this.emit();
    this.update();
    this.render();
  }

  setPosition(x, y) {
    this.x = x;
    this.y = y;
  }
}

