  constructor(cols, rows, cellSize) {
    this.cols = cols;
    this.rows = rows;
    this.cellSize = cellSize;
    this.cells = [];

    this.createGrid();
  }

  createGrid() {
    this.cells = [];

    for (let row = 0; row < this.rows; row++) {
      let rowArray = [];

      for (let col = 0; col < this.cols; col++) {
        let x = col * this.cellSize;
        let y = row * this.cellSize;

        rowArray.push(new Cell(x, y, this.cellSize, false));
      }

      this.cells.push(rowArray);
    }
  }

  getCellAt(col, row) {
    if (col < 0 || col >= this.cols || row < 0 || row >= this.rows) {
      return null;
    }
    return this.cells[row][col];
  }

  toggleCellAtPixel(px, py) {
    const col = floor(px / this.cellSize);
    const row = floor(py / this.cellSize);

    const cell = this.getCellAt(col, row);
    if (cell) {
      cell.toggle();
    }
  }

  setCellAtPixel(px, py, state) {
    const col = floor(px / this.cellSize);
    const row = floor(py / this.cellSize);

    const cell = this.getCellAt(col, row);
    if (cell) {
      cell.setActive(state);
    }
  }

  countActiveNeighbors(col, row) {
    let count = 0;

    for (let yOffset = -1; yOffset <= 1; yOffset++) {
      for (let xOffset = -1; xOffset <= 1; xOffset++) {
        if (xOffset === 0 && yOffset === 0) continue;

        const neighbor = this.getCellAt(col + xOffset, row + yOffset);

        if (neighbor && neighbor.active) {
          count++;
        }
      }
    }

    return count;
  }

  step() {
    // 1. Compute next state for all cells
    for (let row = 0; row < this.rows; row++) {
      for (let col = 0; col < this.cols; col++) {
        const neighbors = this.countActiveNeighbors(col, row);
        this.cells[row][col].computeNextState(neighbors);
      }
    }

    // 2. Apply next state for all cells
    for (let row = 0; row < this.rows; row++) {
      for (let col = 0; col < this.cols; col++) {
        this.cells[row][col].applyNextState();
      }
    }
  }

  render() {
    for (let row = 0; row < this.rows; row++) {
      for (let col = 0; col < this.cols; col++) {
        this.cells[row][col].render();
      }
    }
  }
}

