class Cell {
  constructor(x, y, size, active = false) {
    this.x = x;
    this.y = y;
    this.size = size;

    this.active = active;
    this.nextActive = active;

    this.minSides = 3;
    this.maxSides = 8;

    this.sideValue = active ? this.maxSides : this.minSides;

    this.phase = random(TWO_PI);
    this.rot = random(TWO_PI);
  }

  setActive(state) {
    this.active = state;
    this.nextActive = state;
  }

  toggle() {
    this.active = !this.active;
    this.nextActive = this.active;
  }

  computeNextState(neighborCount) {
    if (this.active) {
      this.nextActive = neighborCount === 2 || neighborCount === 3;
    } else {
      this.nextActive = neighborCount === 3;
    }
  }

  applyNextState() {
    this.active = this.nextActive;
  }

  updateVisual() {
    const target = this.active ? this.maxSides : this.minSides;
    this.sideValue = lerp(this.sideValue, target, 0.18);
  }

  render() {
    this.updateVisual();

    const cx = this.x + this.size * 0.5;
    const cy = this.y + this.size * 0.5;

    const t = frameCount * 0.03 + this.phase;

    noStroke();

    // cell background
    fill(palette[0]);
    rect(this.x, this.y, this.size, this.size);

    push();
    translate(cx, cy);

    rotate(this.rot + t * 0.5);

    const radius = this.size * (0.24 + 0.05 * sin(t * 2.0));
    const sides = max(3, round(this.sideValue));

    // normalize animation for color interpolation
    const lerpAmt = map(this.sideValue, this.minSides, this.maxSides, 0, 1);

    const col = lerpColor(
      color(palette[1]),
      color(palette[2]),
      lerpAmt
    );

    fill(col);

    this.drawPolygon(0, 0, radius, sides);

    pop();
  }

