class Cell {
  constructor(x, y, size, active = false, motifType = 0) {
    this.x = x;
    this.y = y;
    this.size = size;

    this.active = active;
    this.nextActive = active;

    this.motifType = motifType;

    this.phase = random(TWO_PI);
    this.rot = random(TWO_PI);

    this.setMotifConfig();

    this.sideValue = active ? this.maxSides : this.minSides;
  }

  setMotifConfig() {
    if (this.motifType === 0) {
      this.minSides = 3;
      this.maxSides = 8;
      this.rotSpeed = 0.5;
      this.innerScale = 0.52;
      this.pulseAmp = 0.04;
    } else if (this.motifType === 1) {
      this.minSides = 4;
      this.maxSides = 10;
      this.rotSpeed = -0.35;
      this.innerScale = 0.64;
      this.pulseAmp = 0.06;
    } else {
      this.minSides = 6;
      this.maxSides = 12;
      this.rotSpeed = 0.22;
      this.innerScale = 0.42;
      this.pulseAmp = 0.03;
    }
  }

  setActive(state) {
    this.active = state;
    this.nextActive = state;
  }

  computeNextState(neighborCount) {
    if (this.active) {
      this.nextActive = neighborCount === 2 || neighborCount === 3;
    } else {
      this.nextActive = neighborCount === 3;
    }
  }

  applyNextState() {
    this.active = this.nextActive;
  }

  updateVisual() {
    const target = this.nextActive ? this.maxSides : this.minSides;
    this.sideValue = lerp(this.sideValue, target, 0.22);
  }

  render() {
    this.updateVisual();

    const cx = this.x + this.size * 0.5;
    const cy = this.y + this.size * 0.5;
    const t = frameCount * 0.03 + this.phase;

    noStroke();

    fill(palette[0]);
    rect(this.x, this.y, this.size, this.size);

    const lerpAmt = map(this.sideValue, this.minSides, this.maxSides, 0, 1, true);
    const col = lerpColor(color(palette[1]), color(palette[2]), lerpAmt);

    const radius = this.size * (0.33 + this.pulseAmp * sin(t * 2.0));
    const sides = max(3, round(this.sideValue));

    push();
    translate(cx, cy);
    rotate(this.rot + t * this.rotSpeed);

    if (this.motifType === 0) {
      this.renderMotifA(radius, sides, col, t);
    } else if (this.motifType === 1) {
      this.renderMotifB(radius, sides, col, t);
    } else {
      this.renderMotifC(radius, sides, col, t);
    }

    pop();
  }

  renderMotifA(radius, sides, col, t) {
    fill(col);
    this.drawPolygon(0, 0, radius, sides);

    fill(lerpColor(col, color(palette[0]), 0.45));
    this.drawPolygon(0, 0, radius * this.innerScale, max(3, sides - 1));

    fill(col);
    circle(0, 0, this.size * 0.08);
  }

  renderMotifB(radius, sides, col, t) {
    fill(col);
    this.drawPolygon(0, 0, radius, sides);

    push();
    rotate(-t * 0.9);
    fill(lerpColor(col, color(255), 0.25));
    this.drawPolygon(0, 0, radius * this.innerScale, max(3, floor(sides * 0.5)));
    pop();

    push();
    for (let i = 0; i < 4; i++) {
      rotate(HALF_PI * i + t * 0.2);
      rectMode(CENTER);
      fill(lerpColor(col, color(palette[0]), 0.6));
      rect(radius * 0.3, 0, this.size * 0.08, this.size * 0.08);
    }
    pop();
  }

  renderMotifC(radius, sides, col, t) {
    fill(col);
    this.drawPolygon(0, 0, radius, sides);

    fill(lerpColor(col, color(palette[0]), 0.35));
    for (let i = 0; i < 3; i++) {
      push();
      rotate((TWO_PI / 3) * i + t * 0.15);
      this.drawPolygon(radius * 0.36, 0, radius * 0.28, max(3, floor(sides * 0.5)));
      pop();
    }

    fill(lerpColor(col, color(255), 0.2));
    this.drawPolygon(0, 0, radius * 0.22, 3);
  }

  drawPolygon(x, y, r, sides) {
    beginShape();
    for (let i = 0; i < sides; i++) {
      const angle = (TWO_PI * i) / sides - HALF_PI;
      const px = x + cos(angle) * r;
      const py = y + sin(angle) * r;
      vertex(px, py);
    }
    endShape(CLOSE);
  }
}

