        rowArray.push(new Cell(x, y, this.cellSize, active, motifType));
      }

      this.cells.push(rowArray);
    }
  }

  getCellAt(col, row) {
    if (col < 0 || col >= this.cols || row < 0 || row >= this.rows) {
      return null;
    }
    return this.cells[row][col];
  }

  countActiveNeighbors(col, row) {
    let count = 0;

    for (let yOffset = -1; yOffset <= 1; yOffset++) {
      for (let xOffset = -1; xOffset <= 1; xOffset++) {
        if (xOffset === 0 && yOffset === 0) continue;

        const neighbor = this.getCellAt(col + xOffset, row + yOffset);

        if (neighbor && neighbor.active) {
          count++;
        }
      }
    }

    return count;
  }

  step() {
    for (let row = 0; row < this.rows; row++) {
      for (let col = 0; col < this.cols; col++) {
        const neighbors = this.countActiveNeighbors(col, row);
        this.cells[row][col].computeNextState(neighbors);
      }
    }

    for (let row = 0; row < this.rows; row++) {
      for (let col = 0; col < this.cols; col++) {
        this.cells[row][col].applyNextState();
      }
    }
  }

  render() {
    for (let row = 0; row < this.rows; row++) {
      for (let col = 0; col < this.cols; col++) {
        this.cells[row][col].render();
      }
    }
  }
  randomize(prob = 0.4) {
    for (let row = 0; row < this.rows; row++) {
      for (let col = 0; col < this.cols; col++) {
        const cell = this.cells[row][col];

        const state = random() < prob;

        cell.active = state;
        cell.nextActive = state;

        // reset visual interpolation
        cell.sideValue = state ? cell.maxSides : cell.minSides;
      }
    }
  }
}

files.sketch.js:
let grid;
let cellSize = 8;
let cols, rows;
let isRunning = true;

let palette = [
  "#05060a", // cell background
  "#1a1f3a", // inactive glow
  "#00f0ff"  // active glow
];

// mic / audio trigger
let mic;
let micStarted = false;
let audioThreshold = 0.012;   // raise/lower this
let triggerCooldown = 30;    // frames
let lastTriggerFrame = -999;

// start button
let startButton = {
  x: 0,
  y: 0,
  w: 170,
  h: 56,
  visible: true
};

function setup() {
  createCanvas(400, 400);

  cols = floor(width / cellSize);
  rows = floor(height / cellSize);

  grid = new Grid(cols, rows, cellSize);

  startButton.x = width * 0.5;
  startButton.y = height * 0.5;

  frameRate(60);
}

function draw() {
  background(palette[0]);

  if (micStarted) {
    checkMicTrigger();
  }

  if (isRunning && frameCount % 6 === 0) {
    grid.step();
  }

  grid.render();

  if (startButton.visible) {
    drawStartButton();
  }

  drawMicLevel();
}

function checkMicTrigger() {
  if (!mic) return;

  let level = mic.getLevel();

  if (
    level > audioThreshold &&
    frameCount - lastTriggerFrame > triggerCooldown
  ) {
    grid.randomize();
    lastTriggerFrame = frameCount;
  }
}

function drawStartButton() {
  push();
  rectMode(CENTER);
  textAlign(CENTER, CENTER);

  noStroke();
  fill(0, 180);
  rect(startButton.x, startButton.y, startButton.w + 10, startButton.h + 10, 18);

  stroke(0, 240, 255);
  strokeWeight(1.5);
  fill(8, 18, 28);
  rect(startButton.x, startButton.y, startButton.w, startButton.h, 14);

  noStroke();
  fill(0, 240, 255);
  textSize(16);
  text("Start Mic", startButton.x, startButton.y);
  pop();
}

function drawMicLevel() {
  if (!micStarted || !mic) return;

  let level = mic.getLevel();
  let barW = 120;
  let barH = 8;
  let x = 14;
  let y = 14;

  push();
  noStroke();
  fill(255, 30);
  rect(x, y, barW, barH, 4);

  let mapped = constrain(map(level, 0, max(audioThreshold * 1.8, 0.2), 0, barW), 0, barW);

  fill(level > audioThreshold ? "#00f0ff" : "#1a1f3a");
  rect(x, y, mapped, barH, 4);

  noStroke();
  fill(255, 160);
  textSize(10);
  text(`mic: ${nf(level, 1, 3)}  threshold: ${audioThreshold}`, x, y + 20);
  pop();
}

function mousePressed() {
  if (startButton.visible && overStartButton(mouseX, mouseY)) {
    startMic();
  }
}

function overStartButton(px, py) {
  return (
    px > startButton.x - startButton.w * 0.5 &&
    px < startButton.x + startButton.w * 0.5 &&
    py > startButton.y - startButton.h * 0.5 &&
    py < startButton.y + startButton.h * 0.5
  );
}

function startMic() {
  userStartAudio();

  mic = new p5.AudioIn();
  mic.start(
    () => {
      micStarted = true;
      startButton.visible = false;
    },
    (err) => {
      console.error("Mic start failed:", err);
    }
  );
}

function keyPressed() {
  if (key === ' ') {
    isRunning = !isRunning;
  }

  if (key === 'r' || key === 'R') {
    grid.randomize();
  }
}

