class Cell {
  constructor(x, y, size, active = false, motifType = 0) {
    this.x = x;
    this.y = y;
    this.size = size;

    this.active = active;
    this.nextActive = active;

    this.motifType = motifType;

    this.energy = active ? 1 : 0;
    this.phase = random(TWO_PI);
    this.rot = random(TWO_PI);

    this.angleOffset = random(TWO_PI);
    this.orbit = random(0.08, 0.28);
    this.speed = random(0.5, 1.6);
    this.drift = random(0.5, 1.3);
    this.particleSize = random(0.18, 0.32);
  }

  setActive(state) {
    this.active = state;
    this.nextActive = state;
  }

  computeNextState(neighborCount) {
    if (this.active) {
      this.nextActive = neighborCount === 2 || neighborCount === 3;
    } else {
      this.nextActive = neighborCount === 3;
    }
  }

  applyNextState() {
    this.active = this.nextActive;
  }

  updateVisual() {
    const target = this.nextActive ? 1 : 0;
    this.energy = lerp(this.energy, target, 0.18);
  }

  render() {
    this.updateVisual();

    const cx = this.x + this.size * 0.5;
    const cy = this.y + this.size * 0.5;
    const t = frameCount * 0.04 + this.phase;

    noStroke();



    const inactiveCol = color(palette[1]);
    const activeCol = color(palette[2]);
    const glowCol = lerpColor(inactiveCol, activeCol, this.energy);

    const orbitR =
      this.size * (this.orbit * (0.3 + 1.1 * this.energy)) +
      sin(t * this.drift) * this.size * 0.04;

    const a = t * this.speed + this.angleOffset;

    const px = cx + cos(a) * orbitR;
    const py = cy + sin(a) * orbitR;

    const s = this.size * this.particleSize * (0.55 + 1.2 * this.energy);



    // core
    fill(red(glowCol), green(glowCol), blue(glowCol), 255);
    circle(px, py, s);
  }
}

